import supertest from 'supertest';
import app from '@mocks/index'; // Alias import
import logger from '@utils/logger'; // Spy on logger

jest.spyOn(logger, 'info'); // Spy on logger.info

describe('Mock Express App', () => {
  it('should respond to /user/profile endpoint', async () => {
    const response = await supertest(app).get('/user/profile');
    expect(response.status).toBe(200);
    expect(response.body).toEqual({ success: true });
    expect(logger.info).toHaveBeenCalledWith('Mock /user/profile called', expect.any(Object));
  });

  it('should respond to /arbitrators endpoint', async () => {
    const response = await supertest(app).get('/arbitrators');
    expect(response.status).toBe(200);
    expect(response.body).toEqual({ success: true });
    expect(logger.info).toHaveBeenCalledWith('Mock /arbitrators called', expect.any(Object));
  });

  it('should respond to /onboarding endpoint', async () => {
    const response = await supertest(app).get('/onboarding');
    expect(response.status).toBe(200);
    expect(response.body).toEqual({ success: true });
    expect(logger.info).toHaveBeenCalledWith('Mock /onboarding called', expect.any(Object));
  });

  it('should include correlation ID in logs', async () => {
    const response = await supertest(app)
      .get('/user/profile')
      .set('x-correlation-id', 'test-corr');
    expect(response.status).toBe(200);
    expect(logger.info).toHaveBeenCalledWith(expect.any(String), expect.objectContaining({ correlationId: 'test-corr' }));
  });
});
